import React from "react"
import '../collapse.css'
import FullCalendar from '@fullcalendar/react' // must go before plugins
import dayGridPlugin from '@fullcalendar/daygrid' // a plugin!
import interactionPlugin from "@fullcalendar/interaction" // needed for dayClick
import Moment from 'moment'
import Collapsible from "react-collapsible"
import { properties } from '../../properties/properties.js'

var evalValue = []
//var checkedEval = []
var buildEvaluation = []
var indexCheckbox = 0

class Scheduler extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], teamValue: "", screen: 0, dateStr: "", teamId: "", incompleteEval: [], createEvalResult: [], disableSubmitButton: true, statusEval: [], setCalendarDate: ""
        };

    }




        componentDidMount() {


          this.setState({setCalendarDate: Moment().format("YYYY-MM-DD")})


          //console.log(Moment().format("YYYY-MM-DD"))

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            var backUrl = properties.backend + `scheduler/get_schedule`

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({results: response})
                this.setState({screen: 1})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });


          }


          handleDidMount = () => {

            for (let x in this.state.results) {
              var inTomorrow = true
              //content.push(<div>{this.state.results[x].eventDate}</div>)
              //content.push(<div><hr></hr></div>)
              //each team


              for (let y in this.state.results[x].data) {
                  if (!this.state.results[x].data[y].inTomorrow) {
                    inTomorrow = false
                  }
                  for (let z in this.state.results[x].data[y].members) {
                    if (!this.state.results[x].data[y].members[z].inTomorrow) {
                        inTomorrow = false
                    }
                  }
              } 

              var coloring = "blue"

              if (!inTomorrow) {
                /*
                if (findDate != null) {
                  var dateNumber = findDate.getElementsByClassName("fc-daygrid-day-number")
                  for (var i = 0; i < dateNumber.length; i++) {
                    dateNumber[i].style.color = "red"; 
                  }
                }
                */
               coloring = "red"

              }

              var findDate = document.querySelector('[data-date="' + this.state.results[x].eventDate +'"]')
              if (findDate != null) {
                var dateNumber = findDate.getElementsByClassName("fc-daygrid-day-number")
                for (var i = 0; i < dateNumber.length; i++) {
                  dateNumber[i].style.color = coloring; 
                  dateNumber[i].style.fontWeight = "bold";
                }
              }



            }



          }





          handleEventClick = (arg) => { // bind with an arrow function



              this.setState({dateStr: arg.event.startStr})


              this.setState({setCalendarDate: arg.event.startStr})

              this.setState({screen: 0})

              //var evalResult = this.state.results.filter(Record => Record.eventDate === arg.event.startStr)[0].evalResult

              //console.log(dateTeam)
              //this.callStatus(evalResult, 4)
              this.setState({screen: 4})

            //}

          }





          handleDateClick = (arg) => { // bind with an arrow function


                  if (this.state.results.filter(Record => Record.eventDate === arg.dateStr).length > 0) {
                    this.setState({dateStr: arg.dateStr})
                    this.setState({setCalendarDate: arg.dateStr})

                    this.setState({screen: 0})

                    try {

                      //console.log(dateTeam)
                      //this.callStatus(evalResult, 4)

                      this.setState({screen: 4})


                    } catch (e) {
                      this.setState({screen: 4})
                    }
                  } else {
                    alert("Data is not avaliable")
                  }




          }


          goBackFirstScreen = () => {
            this.setState({screen: 1});
          }

          goBackSecondScreen = () => {




            this.setState({screen: 4});
          }

          goBack = () => {



            if (this.state.results.filter(Record => Record.eventDate === Moment(this.state.dateStr, "YYYY-MM-DD").add(-1, 'days').format("YYYY-MM-DD")).length > 0) {

              this.setState({dateStr: Moment(this.state.dateStr, "YYYY-MM-DD").add(-1, 'days').format("YYYY-MM-DD")})

              this.setState({screen: 0})

              this.setState({screen: 4})


            } else {
              alert("Data is not avaliable")
            }

          }


          goForward = () => {




            if (this.state.results.filter(Record => Record.eventDate === Moment(this.state.dateStr, "YYYY-MM-DD").add(1, 'days').format("YYYY-MM-DD")).length > 0) {
              this.setState({dateStr: Moment(this.state.dateStr, "YYYY-MM-DD").add(1, 'days').format("YYYY-MM-DD")})
              //this.setState({screen: 2})
              this.setState({screen: 0})


                this.setState({screen: 4})


            } else {
              alert("Data is not available")
            }

          }








          render() {


            var todayDate = "Loading ..."
            var content = []
            var events = []

            var overLapDayFilter = 5



            if (this.state.screen === 1) {

              todayDate = ""
              for (let x in this.state.results) {
                var inTomorrow = true 
                for (let y in this.state.results[x].data) {
                  if (!this.state.results[x].data[y].inTomorrow) {
                    inTomorrow = false
                  }
                  for (let z in this.state.results[x].data[y].members) {
                    if (!this.state.results[x].data[y].members[z].inTomorrow) {
                      inTomorrow = false
                    }
                  }
                }
                if (!inTomorrow) {
                  events.push({id: "", groupId: this.state.results[x].groupId,title: " - Rotation Change - ",  date: this.state.results[x].eventDate, color: "#FF7F7F", textColor: "black" })
                }

              }


              content.push(                 <FullCalendar
                plugins={[ dayGridPlugin, interactionPlugin ]}
                initialView="dayGridMonth"
                events={events}
                eventClick={this.handleEventClick}
                dateClick={this.handleDateClick}
                eventOrder="id"
                eventDidMount={this.handleDidMount}
                initialDate= {this.state.setCalendarDate}
                //navLinkDayClick={this.handleLinkClick}

              />)



            }


            if (this.state.screen === 3) {
              todayDate = ""
              var dateTeam = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)[0].data.filter(Record => Record.id === this.state.teamId)[0]
              //console.log(dateTeam)
              content.push(<div> <button onClick={() => this.goBackSecondScreen()} style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow"}}>Go Back</button><h3>Date: {dateTeam.date}</h3></div>)

              content.push(<div style={{color: "green", marginBottom: "5px", fontStyle: "bold"}}><h3>{dateTeam.assignment}</h3></div>)
              content.push(<hr></hr>)
              content.push(<div></div>)

              buildEvaluation = []


              var facuColor = "black"
              if (!dateTeam.inTomorrow) {
                facuColor = "red"
              }


              var residentsContent = []
              evalValue = []

              indexCheckbox = 0

              for (let y in dateTeam.members) {

                var colorRes = "black"
                if (!dateTeam.members[y].inTomorrow) {
                  colorRes = "red"
                }


                //residentsContent.push(<div style={{marginLeft: '10px', color: colorRes}}>- {dateTeam.members[y].name} * medHubID: ({dateTeam.members[y].userID}) - programID: {dateTeam.members[y].programID}</div>)

                var noEval = true
                var addResInternToFacultyEval = false

                var typeString = ""

                var createCheckbox = dateTeam.members[y].overlap.filter(Record => Record.name === dateTeam.name)[0].daysTogether >= overLapDayFilter && dateTeam.members[y].programID != "1275"

                if (dateTeam.members[y].resident) {
                  typeString = " - resident"
                  if (!dateTeam.inTomorrow || !dateTeam.members[y].inTomorrow) {
                    if (createCheckbox) {
                      this.makeCheckBox(dateTeam.name,dateTeam.members[y].name,5735,5,dateTeam.userID,dateTeam.members[y].userID,dateTeam.name + " => " + dateTeam.members[y].name + " * IM - UC Wards (Faculty of Resident - New)",dateTeam.members[y].rotationStart,dateTeam.members[y].rotationEnd)
                    }
                    addResInternToFacultyEval = true
                  } 
                }
                if (dateTeam.members[y].intern) {
                  typeString = " - intern"
                  if (!dateTeam.inTomorrow || !dateTeam.members[y].inTomorrow) {
                    if (createCheckbox) {
                      this.makeCheckBox(dateTeam.name,dateTeam.members[y].name,5734,5,dateTeam.userID,dateTeam.members[y].userID,dateTeam.name + " => " + dateTeam.members[y].name + " * IM - UC Wards (Faculty of Intern - New)",dateTeam.members[y].rotationStart,dateTeam.members[y].rotationEnd)
                    }
                    addResInternToFacultyEval = true
                  }
                }

                if (addResInternToFacultyEval) {
                  if (createCheckbox) {
                    this.makeCheckBox(dateTeam.members[y].name,dateTeam.name,5819,2,dateTeam.members[y].userID,dateTeam.userID,dateTeam.members[y].name + " => " + dateTeam.name + " * IM - Trainee Evaluation of Faculty (2019 Respect - Residency/New)",dateTeam.rotationStart,dateTeam.rotationEnd)
                  }
                }







                var rotationString = ""
                if (dateTeam.members[y].rotationStart != undefined && dateTeam.members[y].rotationEnd != undefined) {
                  rotationString = "(Rotation: " + Moment(dateTeam.members[y].rotationStart, "MM-DD-YYYY").format("MM/DD/YY") + " - " + Moment(dateTeam.members[y].rotationEnd, "MM-DD-YYYY").format("MM/DD/YY") + ")"
                }
                residentsContent.push(<div><span  style={{color: colorRes}}>{dateTeam.members[y].name + typeString} {rotationString}</span></div>)
                var statusEval = []
                var evalCount = 0
                for(let m in dateTeam.members[y].evalResult) {
                  rotationString = ""
                  if (dateTeam.members[y].evalResult[m].request.rotationStart != undefined && dateTeam.members[y].evalResult[m].request.rotationEnd != undefined) {
                    rotationString = "(Rotation: " + Moment(dateTeam.members[y].evalResult[m].request.rotationStart, "MM-DD-YYYY").format("MM/DD/YY") + " - " + Moment(dateTeam.members[y].evalResult[m].request.rotationEnd, "MM-DD-YYYY").format("MM/DD/YY") + ")"
                  }
                  statusEval.push(<div><span style={{color: "blue"}}> Issue Date: {dateTeam.members[y].evalResult[m].request.date}:</span> {dateTeam.members[y].evalResult[m].request.title} ({dateTeam.members[y].evalResult[m].request.evaluationID}) - {dateTeam.members[y].evalResult[m].status.status_title} {rotationString}<hr></hr></div>)
                  evalCount += 1
                }

                /*
                for(let m in this.state.statusEval) {
                    if (this.state.statusEval[m].request.evaluator_userID === dateTeam.members[y].userID) {
                      rotationString = ""
                      if (this.state.statusEval[m].request.rotationStart != undefined && this.state.statusEval[m].request.rotationEnd != undefined) {
                        rotationString = "(Rotation: " + Moment(this.state.statusEval[m].request.rotationStart, "MM-DD-YYYY").format("MM/DD/YY") + " - " + Moment(this.state.statusEval[m].request.rotationEnd, "MM-DD-YYYY").format("MM/DD/YY") + ")"
                      }
                      statusEval.push(<div><span style={{color: "blue"}}> Issue Date: {this.state.statusEval[m].request.date}:</span> {this.state.statusEval[m].request.title} ({this.state.statusEval[m].request.evaluationID}) - {this.state.statusEval[m].status.status_title} {rotationString}<hr></hr></div>)
                      evalCount += 1
                    }
                }
                */




                //residentsContent.push(<div>--------------------------------------------------------------------------------------------</div>)
                residentsContent.push(<div style={{height: "10px"}}></div>)

              }


              for (let m in dateTeam.members) {

                for (let n in dateTeam.members) {
                  if (dateTeam.members[m].resident) {
                    if (dateTeam.members[m].name != dateTeam.members[n].name) {
                      //Resident change

                      if (dateTeam.members[m].overlap.filter(Record => Record.name === dateTeam.members[n].name)[0].daysTogether >= overLapDayFilter && dateTeam.members[m].programID != "1275") {
                        if (!dateTeam.members[m].inTomorrow) {
                          this.makeCheckBox(dateTeam.members[m].name,dateTeam.members[n].name,6550,1,dateTeam.members[m].userID,dateTeam.members[n].userID,dateTeam.members[m].name + " => " + dateTeam.members[n].name + " * IM - Resident Feedback for Intern (Peer - Current 6/21)",dateTeam.members[n].rotationStart,dateTeam.members[n].rotationEnd)
                          this.makeCheckBox(dateTeam.members[n].name,dateTeam.members[m].name,6551,1,dateTeam.members[n].userID,dateTeam.members[m].userID,dateTeam.members[n].name + " => " + dateTeam.members[m].name + " * IM - Intern Feedback for Resident (Peer - Current 6/21)",dateTeam.members[m].rotationStart,dateTeam.members[m].rotatoinEnd)
                        } else {
                          if (dateTeam.members[n].intern && !dateTeam.members[n].inTomorrow) {
                            this.makeCheckBox(dateTeam.members[m].name,dateTeam.members[n].name,6550,1,dateTeam.members[m].userID,dateTeam.members[n].userID,dateTeam.members[m].name + " => " + dateTeam.members[n].name + " * IM - Resident Feedback for Intern (Peer - Current 6/21)",dateTeam.members[n].rotationStart,dateTeam.members[n].rotationEnd)
                            this.makeCheckBox(dateTeam.members[n].name,dateTeam.members[m].name,6551,1,dateTeam.members[n].userID,dateTeam.members[m].userID,dateTeam.members[n].name + " => " + dateTeam.members[m].name + " * IM - Intern Feedback for Resident (Peer - Current 6/21)",dateTeam.members[m].rotationStart,dateTeam.members[m].rotatoinEnd)
                          } 
                        }
                      }
                    }
                  }
                }
              }






              content.push(<div><h3>Faculty</h3></div>)

              content.push(<div><span  style={{color: facuColor}}>{dateTeam.name} (Rotation: {Moment(dateTeam.rotationStart,"MM-DD-YYYY").format("MM/DD/YY")} - {Moment(dateTeam.rotationEnd,"MM-DD-YYYY").format("MM/DD/YY")})</span></div>)


              var statusEval = []
              var evalCount = 0

              for(let m in dateTeam.evalResult) {
                if (dateTeam.evalResult[m].request.rotationStart != undefined && dateTeam.evalResult[m].request.rotationEnd != undefined) {
                  rotationString = "(Rotation: " + Moment(dateTeam.evalResult[m].request.rotationStart, "MM-DD-YYYY").format("MM/DD/YY") + " - " + Moment(dateTeam.evalResult[m].request.rotationEnd, "MM-DD-YYYY").format("MM/DD/YY") + ")"
                }
                statusEval.push(<div><span style={{color: "blue"}}> Issue Date: {dateTeam.evalResult[m].request.date}:</span> {dateTeam.evalResult[m].request.title} ({dateTeam.evalResult[m].request.evaluationID}) - {dateTeam.evalResult[m].status.status_title} {rotationString}<hr></hr></div>)
                evalCount += 1
              }





              content.push(<div><h3>Residents / Internship</h3></div>)

              content.push(residentsContent)

              content.push(<div style={{height: "20px"}}></div>)
              content.push(<div><h3>Create Evaluation&nbsp;&nbsp;<button onClick={() => this.handleSubmitEval()} disabled={this.state.disableSubmitButton} id="submitButton" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>submit</button></h3></div>)
              content.push(<hr></hr>)
              content.push(buildEvaluation)
              //this.setState({evalArray: evalValue})




              var showHeader = true
              for (let p in this.state.createEvalResult) {
                  if (showHeader) {
                    content.push(<div>&nbsp;</div>)
                    content.push(<div style={{fontSize: "16px"}}>Result:</div>)
                    content.push(<div><hr></hr></div>)
                    showHeader = false
                  }

                    if (this.state.createEvalResult[p].result.error.length > 0) {
                      content.push(<div style={{color: "red"}}>Result: {this.state.createEvalResult[p].result.error} || {this.state.createEvalResult[p].requestObject.title}</div>)

                    } else {
                      content.push(<div style={{color: "green"}}>Result: Success || {this.state.createEvalResult[p].requestObject.title}</div>)
                    }

              }






            }



            if (this.state.screen === 4) {
              todayDate = ""
              var dateData = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)
              //console.log(dateData)
              for (let index in dateData) {

                content.push(<div><button onClick={() => this.goBackFirstScreen()} style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow"}}>Go Back</button>&nbsp;&nbsp;{dateData[index].formatDate}&nbsp;&nbsp;<button onClick={() => this.goBack()} style={{height: "30px", width: "50px", fontSize: "16px", backgroundColor: "green"}}>&lt;</button>&nbsp;<button onClick={() => this.goForward()} style={{height: "30px", width: "50px", fontSize: "16px", backgroundColor: "green"}}>&gt;</button></div>)
                content.push(<div><hr></hr></div>)
                for (let y in dateData[index].data) {
                  var hasRed = false
                  var colorFaculty = "#000000"
                  if (!dateData[index].data[y].inTomorrow) {
                    colorFaculty = "red"
                    inTomorrow = false
                    hasRed = true 
                  }



                  var residents = []
                  for (let z in dateData[index].data[y].members) {
                    var colorRes = "#000000"
                    if (!dateData[index].data[y].members[z].inTomorrow) {
                        colorRes = "red"
                        inTomorrow = false
                        hasRed = true
                    }
                    //events.push({ title: this.state.results[x].data[y].members[z].name, date: this.state.results[x].eventDate, id: 1, color: "#FF7F7F", textColor: "black" })


                    //overlap
                    var contentWith = "|***| "
                    for (let i in dateData[index].data[y].members[z].overlap) {
                        contentWith += "with (" + dateData[index].data[y].members[z].overlap[i].name + ") " + dateData[index].data[y].members[z].overlap[i].daysTogether + " days |***| "
                    }
                    //content.push(<div style={{color: "blue", fontSize: "12px"}}>{contentWith}</div>)
                    //content.push(<div>&nbsp;</div>)

                    residents.push(<div style={{color: colorRes, fontSize: "14px"}}>--- {dateData[index].data[y].members[z].name_value + " (Rotation: " + Moment(dateData[index].data[y].members[z].rotationStart,"MM-DD-YYYY").format("MM/DD/YY") + " - " + Moment(dateData[index].data[y].members[z].rotationEnd, "MM-DD-YYYY").format("MM/DD/YY") + ")"} --- <span style={{color: "blue"}}>{contentWith}</span></div>)






                    residents.push(<div>&nbsp;</div>)


                  }




                  var buttonCreateEval = []
                  var buttonName = "Create Evaluation"
                  var buttonColor  = "#FF7F7F"



                  content.push(<div style={{color: colorFaculty, fontSize: "14px"}}>{dateData[index].data[y].assignment_value + " - " + dateData[index].data[y].name_value + " (Rotation: " + Moment(dateData[index].data[y].rotationStart, "MM-DD-YYYY").format("MM/DD/YY") + " - " + Moment(dateData[index].data[y].rotationEnd, "MM-DD-YYYY").format("MM/DD/YY") + ")"}&nbsp;&nbsp;{buttonCreateEval}</div>)






                  content.push(<div>&nbsp;</div>)

                  content.push(residents)


                  content.push(<div><hr></hr></div>)
                  //content.push(<div>***************************************************************************************************************************</div>)

                }


              }
            }


            return (






<div style={{minHeight: "500px", marginLeft: "50px"}}><h2 className="display-4 text-center">{todayDate}</h2>{content}</div>


            );
          }


  };

  export default Scheduler
